    10→interface PageProps {
    11→  params: Promise<{ buildId: string }>;
    12→}
    13→
    14→const diffStatusIcons: Record<string, typeof CheckCircle> = {
    15→  pending: AlertTriangle,
    16→  approved: CheckCircle,
    17→  rejected: XCircle,
    18→  auto_approved: CheckCircle,
    19→};
    20→
    21→const diffStatusColors: Record<string, string> = {
    22→  pending: 'text-yellow-600 bg-yellow-50',
    23→  approved: 'text-green-600 bg-green-50',
    24→  rejected: 'text-red-600 bg-red-50',
    25→  auto_approved: 'text-blue-600 bg-blue-50',
    26→};
    27→
    28→export default async function BuildPage({ params }: PageProps) {
    29→  const { buildId } = await params;
    30→  const build = await getBuildSummary(buildId);
    31→  const recentBuilds = await getRecentBuilds(5);
    32→
    33→  if (!build) {
    34→    notFound();
    35→  }
    36→
    37→  const pendingDiffs = build.diffs.filter((d) => d.status === 'pending');
    38→  const failedDiffs = build.diffs.filter((d) => d.status === 'rejected');
    39→  const changedDiffs = build.diffs.filter(
    40→    (d) => d.pixelDifference && d.pixelDifference > 0
    41→  );
    42→
    43→  // Sort: Failed first, then pending changes, then others
    44→  const sortedDiffs = [
    45→    ...failedDiffs,
    46→    ...pendingDiffs.filter((d) => !failedDiffs.includes(d)),
    47→    ...build.diffs.filter(
    48→      (d) => !failedDiffs.includes(d) && !pendingDiffs.includes(d)
    49→    ),
    50→  ];
    51→
    52→  return (
    53→    <div className="p-6 max-w-6xl mx-auto space-y-6">
    54→      {/* Hero Status */}
    55→      <BuildSummaryHero
    56→        status={build.overallStatus}
    57→        changesDetected={build.changesDetected}
    58→      />
    59→
    60→      {/* Metrics Row */}
    61→      <MetricsRow
    62→        totalTests={build.totalTests}
    63→        changesDetected={build.changesDetected}
    64→        flakyCount={build.flakyCount}
    65→        failedCount={build.failedCount}
    66→        elapsedMs={build.elapsedMs}
    67→      />
    68→
    69→      {/* Quick Actions */}
    70→      <div className="flex items-center justify-between">
    71→        <RecentHistory builds={recentBuilds} />
    72→        <BuildActionsClient
    73→          buildId={buildId}
    74→          hasPendingDiffs={pendingDiffs.length > 0}
    75→        />
    76→      </div>
    77→
    78→      {/* Git Info */}
    79→      <div className="p-4 bg-gray-50 rounded-lg text-sm">
    80→        <div className="flex items-center gap-4">
    81→          <div>
    82→            <span className="text-gray-500">Branch:</span>{' '}
    83→            <span className="font-mono">{build.gitBranch}</span>
    84→          </div>
    85→          <div>
    86→            <span className="text-gray-500">Commit:</span>{' '}
    87→            <span className="font-mono">{build.gitCommit.slice(0, 7)}</span>
    88→          </div>
    89→          {build.pullRequestId && (
    90→            <div>
    91→              <span className="text-gray-500">PR:</span>{' '}
    92→              <span className="text-blue-600">#{build.pullRequestId}</span>
    93→            </div>
    94→          )}
    95→        </div>
    96→      </div>
    97→
    98→      {/* Tests for Review */}
    99→      <div>
   100→        <h2 className="text-lg font-semibold mb-4">
   101→          Tests for Review ({sortedDiffs.length})
   102→        </h2>
   103→
   104→        {sortedDiffs.length === 0 ? (
   105→          <div className="text-center py-8 text-gray-500 border rounded-lg">
   106→            No visual changes detected in this build.
   107→          </div>
   108→        ) : (
   109→          <div className="space-y-2">
   110→            {sortedDiffs.map((diff) => {
   111→              const StatusIcon = diffStatusIcons[diff.status];
   112→              const statusColor = diffStatusColors[diff.status];
   113→
   114→              return (
   115→                <Link
   116→                  key={diff.id}
   117→                  href={`/builds/${buildId}/diff/${diff.id}`}
   118→                  className="flex items-center justify-between p-4 border rounded-lg hover:border-blue-300 hover:bg-blue-50/30 transition-colors"
   119→                >
   120→                  <div className="flex items-center gap-3">
   121→                    <div className={`p-2 rounded ${statusColor}`}>
   122→                      <StatusIcon className="w-4 h-4" />
   123→                    </div>
   124→                    <div>
   125→                      <div className="font-medium">Test {diff.testId.slice(0, 8)}</div>
   126→                      <div className="text-sm text-gray-500">
   127→                        {diff.pixelDifference
   128→                          ? `${diff.pixelDifference.toLocaleString()} pixels changed (${diff.percentageDifference}%)`
   129→                          : 'No changes detected'}
   130→                      </div>
   131→                    </div>
   132→                  </div>
   133→
   134→                  <div className="flex items-center gap-4">
   135→                    {diff.currentImagePath && (
   136→                      <img
   137→                        src={diff.currentImagePath}
   138→                        alt="Screenshot"
   139→                        className="w-20 h-12 object-cover rounded border"
   140→                      />
   141→                    )}
   142→                    <ExternalLink className="w-4 h-4 text-gray-400" />
   143→                  </div>
   144→                </Link>
   145→              );
   146→            })}
   147→          </div>
   148→        )}
   149→      </div>
   150→    </div>
   151→  );
   152→}
