     3→import { FileCheck2, AlertTriangle, XCircle, Clock, RefreshCw } from 'lucide-react';
     4→
     5→interface MetricsRowProps {
     6→  totalTests: number;
     7→  changesDetected: number;
     8→  flakyCount: number;
     9→  failedCount: number;
    10→  elapsedMs: number | null;
    11→}
    12→
    13→export function MetricsRow({
    14→  totalTests,
    15→  changesDetected,
    16→  flakyCount,
    17→  failedCount,
    18→  elapsedMs,
    19→}: MetricsRowProps) {
    20→  const formatTime = (ms: number | null) => {
    21→    if (!ms) return '-';
    22→    if (ms < 1000) return `${ms}ms`;
    23→    if (ms < 60000) return `${(ms / 1000).toFixed(1)}s`;
    24→    return `${(ms / 60000).toFixed(1)}m`;
    25→  };
    26→
    27→  const metrics = [
    28→    {
    29→      label: 'Tests',
    30→      value: totalTests,
    31→      icon: FileCheck2,
    32→      color: 'text-blue-600',
    33→      bgColor: 'bg-blue-50',
    34→    },
    35→    {
    36→      label: 'Changed',
    37→      value: changesDetected,
    38→      icon: AlertTriangle,
    39→      color: changesDetected > 0 ? 'text-yellow-600' : 'text-gray-400',
    40→      bgColor: changesDetected > 0 ? 'bg-yellow-50' : 'bg-gray-50',
    41→    },
    42→    {
    43→      label: 'Flaky',
    44→      value: flakyCount,
    45→      icon: RefreshCw,
    46→      color: flakyCount > 0 ? 'text-orange-600' : 'text-gray-400',
    47→      bgColor: flakyCount > 0 ? 'bg-orange-50' : 'bg-gray-50',
    48→    },
    49→    {
    50→      label: 'Failed',
    51→      value: failedCount,
    52→      icon: XCircle,
    53→      color: failedCount > 0 ? 'text-red-600' : 'text-gray-400',
    54→      bgColor: failedCount > 0 ? 'bg-red-50' : 'bg-gray-50',
    55→    },
    56→    {
    57→      label: 'Time',
    58→      value: formatTime(elapsedMs),
    59→      icon: Clock,
    60→      color: 'text-gray-600',
    61→      bgColor: 'bg-gray-50',
    62→      isTime: true,
    63→    },
    64→  ];
    65→
    66→  return (
    67→    <div className="grid grid-cols-5 gap-4">
    68→      {metrics.map((metric) => {
    69→        const Icon = metric.icon;
    70→        return (
    71→          <div
    72→            key={metric.label}
    73→            className={`p-4 rounded-lg ${metric.bgColor} flex flex-col items-center`}
    74→          >
    75→            <div className={`text-3xl font-bold ${metric.color}`}>
    76→              {metric.isTime ? metric.value : metric.value}
    77→            </div>
    78→            <div className="flex items-center gap-1 text-gray-600 text-sm mt-1">
    79→              <Icon className="w-4 h-4" />
    80→              {metric.label}
    81→            </div>
    82→          </div>
    83→        );
    84→      })}
    85→    </div>
    86→  );
    87→}
    88→

